// 内置睡前故事库

class BuiltInStory {
  final String id;
  final String title;
  final String content;
  final String summary;
  final String category;
  final String categoryIcon;
  final int minAge;
  final int maxAge;
  final List<String> tags;

  const BuiltInStory({
    required this.id,
    required this.title,
    required this.content,
    required this.summary,
    required this.category,
    required this.categoryIcon,
    required this.minAge,
    required this.maxAge,
    this.tags = const [],
  });
}

class StoryCategory {
  final String name;
  final String icon;
  final String description;
  const StoryCategory({required this.name, required this.icon, required this.description});
}

const List<StoryCategory> storyCategories = [
  StoryCategory(name: '动物乐园', icon: '🐾', description: '温馨可爱的动物故事'),
  StoryCategory(name: '经典童话', icon: '🏰', description: '充满魔法的童话世界'),
  StoryCategory(name: '勇敢冒险', icon: '🗺️', description: '勇敢的冒险旅程'),
  StoryCategory(name: '温馨日常', icon: '🌙', description: '温暖治愈的日常小故事'),
  StoryCategory(name: '成长启蒙', icon: '📚', description: '寓教于乐的成长故事'),
  StoryCategory(name: '恐龙世界', icon: '🦕', description: '远古恐龙的奇妙世界'),
  StoryCategory(name: '汽车乐园', icon: '🚗', description: '小汽车的有趣故事'),
  StoryCategory(name: '魔法世界', icon: '✨', description: '神奇的魔法故事'),
  StoryCategory(name: '太空探索', icon: '🚀', description: '浩瀚宇宙的旅程'),
  StoryCategory(name: '海洋奇缘', icon: '🌊', description: '海洋深处的冒险'),
];

BuiltInStory _s(String id, String title, String content, String cat, String icon, int min, int max, List<String> tags) {
  return BuiltInStory(
    id: id,
    title: title,
    content: content,
    summary: content.length > 40 ? content.substring(0, 40) : content,
    category: cat,
    categoryIcon: icon,
    minAge: min,
    maxAge: max,
    tags: tags,
  );
}

List<BuiltInStory> get builtInStories {
  return [
    // ==== 动物乐园 ====
    _s('a001', '小兔子的胡萝卜田', '小兔子跳跳住在森林里，每天早上都会去小花园里浇水。有一天，一只小鸟飞来说：小兔子，你能给我一根胡萝卜吗？小兔子开心地给了小鸟一根胡萝卜。小鸟说：谢谢你！你真是好朋友。晚上，小兔子想着：今天帮助了别人，心里真的甜甜的。晚安，小宝贝。', '动物乐园', '🐾', 1, 4, ['兔子', '胡萝卜', '善良']),
    _s('a002', '小熊的蜂蜜罐', '小熊波波最喜欢蜂蜜啦。每天早上，它都会去蜜蜂阿姨那里要一小罐蜂蜜。有一天，波波想自己去找蜂蜜，它走啊走，终于找到了一个大蜂窝。可是蜂窝里的蜜蜂太多了，波波不敢进去。它回家找妈妈，妈妈说：想找蜂蜜要小心，不要打扰蜜蜂阿姨。第二天，波波跟着妈妈去要蜂蜜，终于拿到了甜甜的蜂蜜。晚安，做个甜甜的梦。', '动物乐园', '🐾', 2, 5, ['小熊', '蜂蜜', '勇敢']),
    _s('a003', '小猫咪的毛线球', '小猫咪咪咪最喜欢玩毛线球。妈妈给咪咪买了一个彩色毛线球。咪咪把毛线球抛到天空中，又跳到沙发上再滚到地板上。可是一不小心，毛线球被咪咪弄成了一团乱乱的线团。妈妈说：咪咪，你看你把家里弄乱了，快帮忙收拾一下。咪咪低下头，轻轻地把毛线一根一根地整理好。妈妈笑着说：咪咪真是乖宝贝。晚安，小宝贝。', '动物乐园', '🐾', 2, 5, ['猫咪', '整理', '乖乖']),
    _s('a004', '小狗的骨头', '小狗汪汪有一根最爱骨头。每天它都要把骨头藏在花园里不同的地方，然后第二天再去找出来。有一天，汪汪藏好骨头就跑去玩了。晚上回家想找骨头，可是怎么找也找不到。汪汪着急得团团转。妈妈走过来问：汪汪，你在找什么呀？汪汪说：我心爱的骨头不见了！妈妈笑着说：你昨天把它藏在大树下面啦！汪汪跑过去一看，真的在大树下面！汪汪开心地吃着骨头。晚安，小宝贝。', '动物乐园', '🐾', 2, 6, ['小狗', '骨头', '记忆']),
    _s('a005', '小松鼠的坚果', '小松鼠松松最喜欢收集坚果了。秋天一到，松松就开始忙忙碌碌地把坚果藏起来。有一天，松松找到了一颗大大的坚果，它开心地把它藏在了一个隐秘的地方。可是等到冬天来的时候，松松怎么也找不到那颗坚果了。松松急得团团转。这时候，小鸟飞过来说：松松，你是不是在找你的坚果呀？我帮你一起找吧！他们找啊找，终于在雪地里找到了那颗坚果。松松开心地笑了。晚安，小宝贝。', '动物乐园', '🐾', 3, 7, ['松鼠', '坚果', '友谊']),
    _s('a006', '小狐狸的尾巴', '小狐狸红红有一条漂亮的大尾巴。每天红红最喜欢的事情就是把自己的大尾巴梳得整整齐齐。有一天，红红出去散步，突然下起了大雨。红红赶紧跑回家，可是尾巴已经湿湿的。红红难过地看着自己的尾巴，觉得不漂亮了。妈妈笑着说：没关系，妈妈帮你擦干。妈妈用柔软的毛巾轻轻地把红红的尾巴擦干。红红的尾巴又变成了漂漂亮亮的大尾巴。晚安，小宝贝。', '动物乐园', '🐾', 2, 6, ['狐狸', '尾巴', '爱护']),
    _s('a007', '小刺猬的苹果', '小刺猬刺刺最喜欢吃苹果了。有一天，它去苹果园里找苹果。可是苹果太大太高了，刺刺怎么也够不到。刺刺想了一个办法：它把自己卷成一个小球，然后滚啊滚，终于滚到了苹果树下。可是，苹果还是太高了。刺刺急得团团转。这时候，一只长颈鹿走过来，问：小刺猬，你在做什么？刺刺说：我想要吃苹果，可是太高了。长颈鹿笑着说：我帮你吧！长颈鹿伸长脖子，帮刺刺摘了一个大大的苹果。刺刺开心地吃着甜甜的苹果。晚安，小宝贝。', '动物乐园', '🐾', 3, 7, ['刺猬', '苹果', '助人']),
    _s('a008', '小熊猫的竹子', '小熊猫圆圆最爱吃竹子。每天早上，圆圆都会去竹林里找最新鲜的竹子。有一天，圆圆在竹林里迷路了。它走啊走啊，怎么也找不到回家的路。圆圆着急得快要哭了。这时候，一只老熊猫走过来问：小圆圆，你怎么一个人在这里呀？圆圆说：我迷路了，找不到家了。老熊猫说：来，跟我走吧，我带你回家。老熊猫带着圆圆，沿着熟悉的竹林小路，终于回到了圆圆的家。妈妈开心地抱住圆圆说：我的小宝贝，下次别一个人跑那么远。晚安，小宝贝。', '动物乐园', '🐾', 3, 8, ['熊猫', '竹子', '迷路']),
    _s('a009', '小鸟的歌声', '小鸟咕咕有一副美妙的歌喉。每天清晨，咕咕都会在树枝上唱歌。森林里的小动物们都喜欢听咕咕唱歌。有一天，咕咕嗓子不舒服，唱不出歌来了。咕咕难过地低下了头。小松鼠松松看到了，问道：咕咕，你怎么啦？咕咕说：我嗓子不舒服，不能唱歌了。松松说：没关系，你好好休息，等你好了再唱给我们听吧。过了几天，咕咕的嗓子终于好了。它又站在树枝上唱起了美妙的歌声。森林里的小动物们都开心极了。晚安，小宝贝。', '动物乐园', '🐾', 3, 8, ['小鸟', '唱歌', '友谊']),
    _s('a010', '小猴子的桃子', '小猴子淘淘最喜欢吃桃子了。山上有一棵大桃树，上面结满了红红的桃子。有一天，淘淘想要去摘桃子。它爬呀爬，终于爬到了桃树上。可是，桃树上的桃子太多了，淘淘挑花了眼，挑了半天也不知道挑哪一个好。这时候，一只老猴子走过来问：淘淘，你在干什么呀？淘淘说：我想要吃桃子，可是不知道挑哪个好。老猴子笑着说：挑最红最大的那个吧。淘淘挑了一个最红最大的桃子，开心地吃了起来。桃子甜甜的，真好吃。晚安，小宝贝。', '动物乐园', '🐾', 3, 7, ['猴子', '桃子', '选择']),
    _s('a011', '小鸭子的池塘', '小鸭子呱呱住在池塘边。每天早上，呱呱都会去池塘里游泳。池塘里的水清清的，凉凉的，呱呱在里面游来游去。有一天，一只小鸭子迷路了，找不到妈妈了。呱呱着急得团团转。这时候，鸭妈妈游过来，看到了呱呱。鸭妈妈说：呱呱，你在这里呀！呱呱开心地游到了鸭妈妈身边。鸭妈妈带着呱呱，一起在池塘里游来游去。晚安，小宝贝。', '动物乐园', '🐾', 2, 6, ['鸭子', '池塘', '妈妈']),
    _s('a012', '小青蛙的荷叶', '小青蛙呱呱住在池塘里的一片大荷叶上。每天晚上，呱呱都会坐在荷叶上看月亮。月亮圆圆的，亮亮的，像一个大大的银盘。有一天，呱呱想要去池塘对面的另一片荷叶上。可是，池塘里的水太深了，呱呱怎么也游不过去。呱呱着急得团团转。这时候，一只大乌龟游过来问：小青蛙，你在干什么呀？呱呱说：我想要去对面的荷叶上。大乌龟说：我背你过去吧。大乌龟背着呱呱，游到了对面的荷叶上。呱呱坐在荷叶上，看着天上的月亮，开心地笑了。晚安，小宝贝。', '动物乐园', '🐾', 3, 7, ['青蛙', '荷叶', '帮助']),
    _s('a013', '小企鹅的冰屋', '小企鹅冰冰住在南极。南极到处都是白茫茫的一片，到处都是冰和雪。冰冰住在一个用冰做的小屋里。有一天，冰冰想要去海边玩。可是外面太冷了，冰冰走了一会儿就冻得发抖。这时候，企鹅妈妈走过来，把冰冰抱在怀里，用自己温暖的羽毛给冰冰取暖。冰冰觉得好暖和呀。妈妈笑着说：我的小宝贝，下次出门要多穿衣服。晚安，小宝贝。', '动物乐园', '🐾', 3, 8, ['企鹅', '南极', '妈妈爱']),
    _s('a014', '小考拉的桉树', '小考拉懒懒住在一棵高高的桉树上。每天，懒懒都要在桉树上睡很长很长的觉。有一天，懒懒醒了，想要吃桉树叶。可是，懒懒发现桉树上的叶子都被吃光了。懒懒难过地低下了头。这时候，一只大考拉走过来，给了懒懒一片嫩嫩的桉树叶。懒懒开心地吃了起来。桉树叶嫩嫩的，真好吃。晚安，小宝贝。', '动物乐园', '🐾', 3, 8, ['考拉', '桉树', '分享']),
    _s('a015', '小海豚的海浪', '小海豚跃跃住在大海里。跃跃最喜欢的事情就是在海浪里跳来跳去。有一天，跃跃在海浪里跳啊跳，一不小心跳到了沙滩上。跃跃着急得想要回到海里，可是怎么也回不去。这时候，一只大海龟游过来说：小海豚，你怎么跑到沙滩上来啦？跃跃说：我跳得太高了，不小心跳到了沙滩上。大海龟笑着说：我帮你推回海里吧。大海龟用自己大大的壳，把跃跃推回了海里。跃跃又开心地在海浪里跳来跳去了。晚安，小宝贝。', '动物乐园', '🐾', 4, 9, ['海豚', '海浪', '帮助']),
    _s('a016', '小鹿的角', '小鹿花花头上有一对漂亮的鹿角。每天花花都会在森林里跑跳。有一天，花花在森林里跑跳的时候，鹿角不小心被树枝卡住了。花花用力拽，可是怎么也拽不出来。花花着急得快要哭了。这时候，一只老山羊走过来问：花花，你怎么啦？花花说：我的角被树枝卡住了。老山羊笑着说：别着急，我帮你。老山羊用自己的角，帮花花把树枝弄开了。花花终于可以跑跳了。晚安，小宝贝。', '动物乐园', '🐾', 3, 8, ['鹿', '鹿角', '助人']),
    _s('a017', '大象的鼻子', '大象灰灰有一条长长的鼻子。灰灰最喜欢用鼻子卷东西。有一天，灰灰的朋友小兔子跳跳不见了。灰灰着急得团团转。灰灰用鼻子四处寻找。终于，灰灰在一片草丛里找到了跳跳。灰灰用鼻子轻轻地把跳跳抱了起来。跳跳开心地说：谢谢你，灰灰！灰灰笑着说：不用谢，我们是好朋友。晚安，小宝贝，好朋友要互相帮助。', '动物乐园', '🐾', 4, 9, ['大象', '鼻子', '友谊']),
    _s('a018', '小狮子的鬃毛', '小狮子金金有一头金色的鬃毛。每天金金都会把自己的鬃毛梳理得整整齐齐。有一天，金金在森林里散步，突然遇到了一只小斑马。小斑马斑斑说：金金，你的鬃毛真漂亮！金金笑着说：谢谢！你的条纹也很漂亮呀！他们两个成为了好朋友。他们一起在森林里跑啊跳啊，玩得非常开心。晚安，小宝贝。', '动物乐园', '🐾', 3, 8, ['狮子', '鬃毛', '友谊']),
    _s('a019', '小老虎的斑纹', '小老虎斑斑身上有一条条漂亮的黑色斑纹。斑斑最喜欢在森林里练习跑跳。有一天，斑斑在森林里跑跳的时候，遇到了一只小豹子。小豹子花花说：斑斑，你的斑纹真漂亮！斑斑笑着说：谢谢！你的斑点也很漂亮呀！他们两个成为了好朋友。他们一起在森林里练习跑跳。晚安，小宝贝。', '动物乐园', '🐾', 4, 10, ['老虎', '斑纹', '友谊']),
    _s('a020', '小斑马的条纹', '小斑马纹纹身上有一条条漂亮的黑白条纹。纹纹最喜欢在草原上跑跳。有一天，纹纹在草原上遇到了一只小斑马。他们一起玩，一起吃草，一起喝水。他们玩得真开心。他们约定，每天都要一起玩。晚安，小宝贝。', '动物乐园', '🐾', 3, 8, ['斑马', '条纹', '玩耍']),
    _s('a021', '小熊的生日', '今天是小熊波波的生日。波波的妈妈给波波做了一个大大的蜂蜜蛋糕。波波的朋友们都来参加波波的生日派对。小兔子跳跳，小猫咪咪咪，小狗汪汪，小松鼠松松都来了。大家一起唱生日歌，一起吹蜡烛，一起吃蛋糕。波波开心得不得了。波波说：这是我最开心的生日！晚安，小宝贝，生日快乐。', '动物乐园', '🐾', 2, 7, ['小熊', '生日', '派对']),
    _s('a022', '小袋鼠的口袋', '小袋鼠袋袋的妈妈肚子上有一个大大的口袋。袋袋最喜欢的就是待在妈妈的口袋里。有一天，妈妈带着袋袋去森林里散步。袋袋在妈妈的口袋里看外面的世界。森林里的世界真奇妙呀。有高大的树木，有五颜六色的花朵，有各种各种的小鸟在唱歌。袋袋开心得不得了。晚安，小宝贝。', '动物乐园', '🐾', 2, 6, ['袋鼠', '口袋', '妈妈']),

    // ==== 经典童话 ====
    _s('f001', '月亮上的小兔子', '很久很久以前，在月亮上住着一只可爱的小兔子。小兔子每天都在月亮上捣药。有一天，小兔子想要去地球上看看。它从月亮上跳了下来，轻轻地落到了地球上。地球上的世界真美丽呀，有绿绿的草地，有五颜六色的花朵，有小鸟在唱歌。小兔子开心得不得了。可是，玩着玩着，小兔子想要回家了。月亮妈妈在天上看着小兔子，笑着说：我的小宝贝，该回家啦。小兔子一跳，又跳回了月亮上。晚安，小宝贝。', '经典童话', '🏰', 2, 6, ['月亮', '兔子', '童话']),
    _s('f002', '小星星', '天上有一颗小小的星星，它每晚都要一闪一闪的。有一天，小星星想要去地球上玩。它从天上跳了下来，落到了一棵树上。树上的树叶沙沙作响，好像在欢迎小星星。小星星在树上闪啊闪，开心极了。玩了一会儿，小星星想要回家了。它一跳，又跳回了天上。天上的月亮妈妈笑着说：小宝贝，你回来啦！晚安，小宝贝。', '经典童话', '🏰', 1, 5, ['星星', '天空', '童话']),
    _s('f003', '会飞的小天使', '从前有一个可爱的小天使，他住在天上的云朵里。每天小天使都要在天空中飞来飞去。有一天，小天使看到了一个小男孩在哭。小天使飞过去问：小朋友，你怎么啦？小男孩说：我迷路了，找不到家了。小天使笑着说：我带你回家吧。小天使带着小男孩，飞啊飞，终于飞到了小男孩的家。妈妈开心地抱住了小男孩。晚安，小宝贝。', '经典童话', '🏰', 3, 8, ['天使', '飞翔', '帮助']),
    _s('f004', '魔法森林', '在一片茂密的森林深处，有一个魔法森林。魔法森林里住着许多神奇的动物们。有一天，一个小女孩走进了魔法森林。小女孩看到了会说话的大树，看到了会跳舞的花朵，还看到了会唱歌的小鸟。小女孩在魔法森林里玩得真开心。到了晚上，小女孩想要回家了。魔法森林里的动物们都来送小女孩回家。晚安，小宝贝。', '经典童话', '🏰', 3, 8, ['森林', '魔法', '冒险']),
    _s('f005', '灰姑娘', '从前有一个善良的小女孩，她的名字叫灰姑娘。灰姑娘每天都要做很多家务，可是她从来没有抱怨过。有一天，皇宫里要举行盛大的舞会。灰姑娘也想去参加舞会。可是她没有漂亮的衣服穿。这时候，一位仙女出现了。仙女用魔法把南瓜变成了马车，把老鼠变成了马，还把灰姑娘的旧衣服变成了漂亮的礼服。灰姑娘穿着漂亮的礼服去参加舞会。舞会上，王子和灰姑娘一起跳舞。午夜钟声响起的时候，灰姑娘匆匆忙忙地回家，留下了一只水晶鞋。最后王子找到了灰姑娘，他们幸福地生活在了一起。晚安，小宝贝。', '经典童话', '🏰', 4, 10, ['灰姑娘', '舞会', '善良']),
    _s('f006', '白雪公主', '在遥远的王国里，住着一位美丽的公主，她的名字叫白雪公主。白雪公主的皮肤像雪一样白，嘴唇像樱桃一样红。有一天，邪恶的皇后想要害白雪公主。白雪公主逃到了森林里。森林里住着七个小矮人。七个小矮人收留了白雪公主。他们一起生活，一起唱歌，一起跳舞。后来，一位英俊的王子救了白雪公主。他们幸福地生活在了一起。晚安，小宝贝。', '经典童话', '🏰', 4, 10, ['白雪公主', '七个小矮人', '善良']),
    _s('f007', '小红帽', '从前有一个小女孩，她总是戴着一顶红色的帽子，大家都叫她小红帽。有一天，小红帽要去看望生病的外婆。妈妈告诉小红帽要走大路，不要走小路。可是小红帽在大路上遇到了一只大灰狼。大灰狼骗小红帽说：小红帽，你看路边的花朵多美丽呀，去摘几朵给外婆吧。小红帽听了大灰狼的话，走到小路上去摘花朵了。大灰狼趁机跑到外婆家，把外婆吞进了肚子里。然后大灰狼又假装成外婆躺在床上。小红帽到了外婆家，发现外婆变得很奇怪。最后，一个猎人过来救了小红帽和外婆。晚安，小宝贝。', '经典童话', '🏰', 4, 10, ['小红帽', '外婆', '小心']),
    _s('f008', '三只小猪', '从前有三只小猪。有一天，他们决定各自盖一间房子。老大用稻草盖了一间房子，老二用木头盖了一间房子，老三用砖头盖了一间房子。大灰狼来了，他一吹，稻草房子就倒了。老大就跑到老二家。大灰狼又吹，木房子也倒了。老大和老二又跑到老三家。大灰狼怎么也吹不倒砖头房子。最后，大灰狼掉进了烟囱里。三只小猪终于安全了。晚安，小宝贝，做事要认真，不要偷懒。', '经典童话', '🏰', 3, 8, ['小猪', '房子', '认真']),
    _s('f009', '丑小鸭', '从前有一只小鸭子，它长得非常丑。其他的小鸭子都欺负它。丑小鸭难过地离开了家。丑小鸭在外面经历了很多困难。可是，丑小鸭并没有放弃。后来，丑小鸭长大了，变成了一只美丽的天鹅。原来，它不是一只小鸭子，而是一只天鹅。天鹅飞在天空中，其他的天鹅们都围过来欢迎它。晚安，小宝贝，每个人都有自己美丽的一面。', '经典童话', '🏰', 3, 8, ['丑小鸭', '天鹅', '成长']),
    _s('f010', '拇指姑娘', '从前有一个小女孩，她只有大拇指那么大。大家都叫她拇指姑娘。有一天，一只癞蛤蟆把拇指姑娘带到了池塘边。拇指姑娘在池塘边遇到了一条大鱼。大鱼帮拇指姑娘逃了出来。后来拇指姑娘遇到了一位花仙子。花仙子让拇指姑娘成为了花朵王国的女王。晚安，小宝贝，小小的你也是独一无二的。', '经典童话', '🏰', 3, 8, ['拇指姑娘', '花朵', '奇遇']),
    _s('f011', '龟兔赛跑', '从前有一只小兔子和一只小乌龟。有一天，小兔子和小乌龟比赛跑步。小兔子跑得很快，小乌龟跑得很慢。小兔子跑了一会儿，回头看不到小乌龟了。小兔子觉得自己赢定了。小兔子就想在路边睡一会儿。可是等小兔子醒来的时候，小乌龟已经跑到终点了。小乌龟赢了比赛。晚安，小宝贝，不要骄傲，也不要偷懒。', '经典童话', '🏰', 2, 7, ['乌龟', '兔子', '比赛']),
    _s('f012', '狼来了', '从前有一个放羊的小孩。有一天，小孩觉得很无聊，就大喊：狼来了！狼来了！山下的大人们听到喊声，都跑上山来。结果发现狼没有来。小孩觉得这样玩很有趣。过了几天，小孩又大喊：狼来了！狼来了！大人们又跑上来。结果发现还是没有狼。又过了几天，真的狼来了。小孩大喊：狼来了！狼来了！可是大人们再也不相信小孩了。最后，小孩的羊都被狼吃掉了。晚安，小宝贝，不要说谎话。', '经典童话', '🏰', 3, 8, ['放羊的小孩', '说谎', '诚实']),
    _s('f013', '青蛙王子', '从前有一位公主，她在池塘边玩金球的时候，不小心把金球掉进了水里。一只青蛙帮公主捡回了金球。青蛙要求公主和它做朋友。公主答应了。后来，公主把青蛙带回了王宫。在王宫里，公主让青蛙坐在餐桌旁和她一起吃饭。青蛙真的变成了一位英俊的王子。原来王子被一个邪恶的巫婆施了魔法。只有公主的善良才能解除魔法。晚安，小宝贝，做人要守信用，要善良。', '经典童话', '🏰', 4, 10, ['青蛙王子', '公主', '善良']),
    _s('f014', '皇帝的新衣', '从前有一位皇帝，他非常喜欢穿漂亮的衣服。有一天，两个骗子说他们能做出世界上最漂亮的衣服。可是，这件衣服只有聪明的人才能看见，愚蠢的人看不见。皇帝派了几位大臣去看衣服。大臣们都看不见衣服，可是他们都不敢说自己看不见。最后，皇帝穿着这件衣服出去游行。街上的人们都不敢说皇帝没有穿衣服。直到一个小孩大声说：皇帝没穿衣服呀！晚安，小宝贝，要诚实，不要怕说真话。', '经典童话', '🏰', 4, 10, ['皇帝的新衣', '诚实', '真话']),
    _s('f015', '金斧头银斧头', '从前有一个诚实的樵夫。有一天，樵夫在河边砍柴的时候，不小心把斧头掉进了河里。樵夫坐在河边哭了起来。这时候，河里出来了一位河神。河神问樵夫为什么哭。樵夫说：我的斧头掉进河里了。河神从河里捞出来一把金斧头，问樵夫是不是他的。樵夫说不是。河神又捞出来一把银斧头，问樵夫是不是他的。樵夫说也不是。最后河神捞出来一把铁斧头。樵夫说这才是他的。河神看樵夫很诚实，就把金斧头和银斧头都送给了樵夫。晚安，小宝贝，诚实会有好报。', '经典童话', '🏰', 3, 8, ['金斧头', '诚实', '奖励']),

    // ==== 勇敢冒险 ====
    _s('b001', '勇敢的小骑士', '从前有一个小男孩叫明明。明明梦想成为一个勇敢的骑士。有一天，村子里来了一个怪物。怪物抢走了村子里的食物。明明决定去打败怪物。明明穿上了盔甲，拿上了剑。明明找到了怪物的山洞。明明勇敢地走进了山洞。山洞里黑漆漆的。明明慢慢地走到了怪物面前。怪物看上去很可怕。可是明明一点也不害怕。明明大声说：快把食物还给我们！怪物看到明明这么勇敢，吓得跑走了。明明把食物带回了村子。村子里的人们都欢呼起来。明明成为了村子里的英雄。晚安，小宝贝，勇敢会给你力量。', '勇敢冒险', '🗺️', 4, 10, ['骑士', '勇敢', '英雄']),
    _s('b002', '小小探险家', '有一个小男孩叫乐乐。乐乐最喜欢探险了。有一天，乐乐听说在森林的深处有一座神秘的城堡。乐乐决定去寻找这座城堡。乐乐带上了地图和水壶。乐乐走进了森林。森林里有高大的树木，有美丽的花朵，还有小鸟在唱歌。乐乐走啊走啊，走到了一条小河边。河水很深。乐乐想了一个办法：他找到了一根很长的树枝，用树枝在水里试探着走了过去。然后，乐乐又翻过了一座小山。终于，乐乐看到了那座神秘的城堡。城堡真漂亮呀！乐乐开心地笑了。晚安，小宝贝，有梦想就要勇敢去追。', '勇敢冒险', '🗺️', 4, 10, ['探险', '森林', '城堡']),
    _s('b003', '勇敢的小火车', '有一辆小火车叫欢欢。欢欢最喜欢在铁路上跑。有一天，欢欢要运送很多货物到山上的小镇。山路很陡。欢欢跑啊跑啊，慢慢地爬到了半山腰。可是货物太重了，欢欢爬不动了。欢欢想：我不能放弃，我一定能行！欢欢鼓起勇气，用力地向上爬。一步一步，一步一步。最后，欢欢终于爬到了山顶！小镇上的人们都在等待着欢欢。他们看到欢欢来了，都开心地欢呼起来。晚安，小宝贝，坚持就是胜利。', '勇敢冒险', '🗺️', 3, 8, ['小火车', '勇敢', '坚持']),
    _s('b004', '小飞机的旅程', '有一架小飞机叫飞飞。飞飞最喜欢在天空中飞翔。有一天，飞飞要去一个很远的地方。飞飞飞啊飞啊，飞过了高山，飞过了河流，飞过了田野。可是，飞飞飞了很久很久，飞飞有点累了。飞飞想：我要不要休息一下？这时候，飞飞看到了一只小鸟。小鸟对飞飞说：小飞机，加油！你一定能飞到目的地的。飞飞听了小鸟的话，又鼓起了勇气。飞飞继续向前飞。最后，飞飞终于飞到了目的地。晚安，小宝贝，累的时候可以休息，但不要放弃。', '勇敢冒险', '🗺️', 4, 10, ['飞机', '旅程', '坚持']),
    _s('b005', '勇敢的小熊', '小熊波波和妈妈去森林里散步。走着走着，波波发现妈妈不见了。波波着急得快要哭了。可是波波想：我不能哭，我要勇敢。波波开始回忆妈妈带自己走过的路。波波看到了一棵大树，妈妈曾经说这是森林的入口。波波沿着大树的方向走去。走啊走啊，波波终于看到了妈妈。妈妈也在找波波。妈妈抱着波波说：我的小宝贝，你真勇敢！晚安，小宝贝，遇到困难不要慌，冷静思考就会有办法。', '勇敢冒险', '🗺️', 3, 8, ['小熊', '勇敢', '迷路']),
    _s('b006', '海底探险', '有一只小海豚叫跃跃。跃跃最喜欢在海里探险。有一天，跃跃听说在大海的深处有一个美丽的珊瑚王国。跃跃决定去寻找这个珊瑚王国。跃跃游啊游啊，游过了浅海，游过了深海。海里有各种各样的鱼，有五颜六色的珊瑚，还有慢悠悠的海龟。跃跃觉得海底世界真美丽呀。最后，跃跃终于找到了那个美丽的珊瑚王国。珊瑚王国里的小鱼们都欢迎跃跃的到来。跃跃开心得不得了。晚安，小宝贝，美丽的世界等你来发现。', '勇敢冒险', '🗺️', 4, 10, ['海豚', '海底', '探险']),
    _s('b007', '勇敢的小船', '有一只小船叫悠悠。悠悠最喜欢在湖上漂流。有一天，悠悠想要去看看湖的对面是什么样子。悠悠从岸边出发，开始了它的旅程。湖上的风有点大，波浪也有点大。悠悠被风吹得摇摇晃晃。可是悠悠一点也不害怕。悠悠努力地向前划。划啊划啊，划啊划啊。最后，悠悠终于划到了湖的对面。湖的对面是一座美丽的小岛。小岛上开满了鲜花，还有小鸟在唱歌。悠悠开心地笑了。晚安，小宝贝，坚持就会有收获。', '勇敢冒险', '🗺️', 3, 8, ['小船', '勇敢', '坚持']),
    _s('b008', '小登山家', '有一个小男孩叫勇勇。勇勇最喜欢爬山了。有一天，勇勇想要去爬一座高高的山。勇勇准备好了背包和水壶。勇勇开始爬山。山上的路很陡。勇勇一步一步地往上爬。爬啊爬啊，勇勇有点累了。勇勇坐在一块大石头上休息。休息了一会儿，勇勇又继续往上爬。最后，勇勇终于爬到了山顶。从山顶看下去，山下的世界真美丽呀。勇勇开心地大喊：我做到啦！晚安，小宝贝，努力就会成功。', '勇敢冒险', '🗺️', 4, 10, ['登山', '勇敢', '努力']),

    // ==== 温馨日常 ====
    _s('w001', '妈妈的晚安吻', '今天晚上，小宝贝玩得有点累了。妈妈走过来，轻轻抱着小宝贝。妈妈给小宝贝讲了一个小故事。然后，妈妈轻轻地在小宝贝额头上亲了一下。妈妈说：晚安，我的小宝贝。小宝贝也对妈妈说：晚安，妈妈。小宝贝闭上眼睛，慢慢地进入了甜甜的梦乡。晚安，小宝贝，妈妈的爱永远在你身边。', '温馨日常', '🌙', 1, 6, ['妈妈', '晚安吻', '爱']),
    _s('w002', '爸爸的故事', '今天晚上，爸爸坐在小宝贝的床边。爸爸给小宝贝讲了一个关于月亮的故事。爸爸说：月亮上住着一只可爱的小兔子，小兔子每天晚上都在捣药。小宝贝听着听着，眼睛就慢慢闭上了。爸爸看到小宝贝睡着了，轻轻地盖好了被子。晚安，小宝贝，爸爸的故事会陪你入梦。', '温馨日常', '🌙', 1, 6, ['爸爸', '故事', '爱']),
    _s('w003', '温暖的小屋', '今天外面下着小雪。小宝贝和爸爸妈妈一起待在温暖的小屋里。屋子里开着暖气，暖暖的。妈妈给小宝贝准备了一杯热牛奶。爸爸给小宝贝讲了一个温馨的故事。小宝贝躺在温暖的床上，看着窗外的雪花。雪花轻轻地飘落在窗台上。小宝贝慢慢地闭上了眼睛。晚安，小宝贝，家永远是你最温暖的港湾。', '温馨日常', '🌙', 1, 5, ['家', '温暖', '雪']),
    _s('w004', '好朋友的生日', '今天是小宝贝好朋友的生日。小宝贝给好朋友准备了一份礼物。礼物是小宝贝亲手画的一幅画。画上有太阳，有花朵，还有小宝贝和好朋友一起玩耍的场景。好朋友收到了礼物，开心地说：谢谢你！这是我收到的最好的礼物。小宝贝也开心地笑了。晚上，小宝贝躺在床上，想着今天的快乐时光。晚安，小宝贝，有朋友真好。', '温馨日常', '🌙', 2, 7, ['朋友', '生日', '友谊']),
    _s('w005', '温馨的晚餐', '今天晚上，妈妈做了一桌丰盛的晚餐。有小宝贝最喜欢的番茄鸡蛋，有香香的米饭，还有一碗热乎乎的汤。爸爸下班回来了。一家人围着餐桌，开心地吃着晚餐。妈妈问小宝贝：今天在幼儿园玩得开心吗？小宝贝开心地说着今天的经历。爸爸笑着听着。晚餐真温馨呀。晚安，小宝贝，一家人在一起最幸福了。', '温馨日常', '🌙', 1, 6, ['晚餐', '家人', '爱']),
    _s('w006', '温暖的阳光', '今天天气真好。温暖的阳光透过窗户照进了屋子里。小宝贝坐在窗边，看着外面的世界。外面有小鸟在唱歌，有小朋友在玩耍，还有美丽的花朵。小宝贝对妈妈说：妈妈，今天的阳光真温暖呀。妈妈笑着说：是啊，阳光就像妈妈的爱一样温暖。小宝贝开心地笑了。晚上，小宝贝躺在温暖的床上，想着今天的阳光，慢慢地睡着了。晚安，小宝贝。', '温馨日常', '🌙', 1, 5, ['阳光', '温暖', '爱']),
    _s('w007', '和爷爷一起', '今天下午，爷爷来小宝贝家了。爷爷带小宝贝去公园玩。爷爷牵着小宝贝的手，慢慢地走在公园里。公园里有绿绿的草地，有漂亮的花朵，还有可爱的小鸟。爷爷给小宝贝买了一个冰淇淋。冰淇淋甜甜的，真好吃。爷爷还给小宝贝讲了小时候的故事。小宝贝听得很入迷。晚上，小宝贝躺在床上，想着今天和爷爷一起的快乐时光。晚安，小宝贝。', '温馨日常', '🌙', 2, 7, ['爷爷', '公园', '亲情']),
    _s('w008', '和奶奶一起', '今天下午，奶奶给小宝贝织了一件小毛衣。小毛衣软软的，暖暖的。奶奶把小毛衣套在小宝贝身上，大小刚刚好。奶奶笑着说：我的小宝贝穿这件小毛衣真好看。小宝贝开心地在奶奶脸上亲了一下。奶奶又给小宝贝准备了一碗甜甜的糖水。晚上，小宝贝穿着温暖的小毛衣，躺在床上，慢慢地睡着了。晚安，小宝贝，奶奶的爱真温暖。', '温馨日常', '🌙', 1, 6, ['奶奶', '毛衣', '爱']),
    _s('w009', '快乐的星期天', '今天是星期天。小宝贝和爸爸妈妈一起去公园玩。公园里有好多小朋友。小宝贝和小朋友们一起玩耍，一起跑步，一起荡秋千。玩累了，爸爸妈妈带小宝贝去吃小宝贝最喜欢的汉堡。下午，一家人又去了书店。爸爸给小宝贝买了一本新的图画书。晚上，小宝贝躺在床上，看着新的图画书，慢慢地睡着了。晚安，小宝贝，星期天真快乐。', '温馨日常', '🌙', 2, 7, ['星期天', '快乐', '家人']),
    _s('w010', '星星和月亮', '今天晚上，小宝贝和妈妈一起在阳台上看星星。天上的星星闪闪的，像一颗颗小宝石。月亮圆圆的，亮亮的，像一个大大的银盘。妈妈指着天上的星星对小宝贝说：你看，那是北斗七星，它们像一个小勺子。小宝贝认真地看着。晚风轻轻地吹着。小宝贝觉得好舒服。过了一会儿，小宝贝有点困了。妈妈带着小宝贝回到房间。小宝贝躺在床上，想着天上的星星，慢慢地睡着了。晚安，小宝贝。', '温馨日常', '🌙', 1, 6, ['星星', '月亮', '夜晚']),

    // ==== 成长启蒙 ====
    _s('g001', '学会分享', '今天，小宝贝的好朋友来家里玩。小宝贝有一个新的玩具车。妈妈对小宝贝说：小宝贝，和好朋友一起玩吧。小宝贝想了想，把玩具车递给了好朋友。好朋友开心地说：谢谢你！他们一起玩着玩具车，玩得真开心。晚上，小宝贝对妈妈说：妈妈，和好朋友一起玩真开心。妈妈笑着说：是啊，分享是一件快乐的事情。晚安，小宝贝，学会分享，快乐会加倍。', '成长启蒙', '📚', 2, 7, ['分享', '朋友', '快乐']),
    _s('g002', '学会道歉', '今天，小宝贝和好朋友一起玩的时候，不小心把好朋友的玩具弄坏了。好朋友难过地哭了。小宝贝看着好朋友，心里很愧疚。妈妈对小宝贝说：小宝贝，去和好朋友说声对不起吧。小宝贝走到好朋友身边，小声说：对不起，我不是故意的。好朋友抬起头说：没关系。妈妈帮他们修好了玩具。他们又开心地一起玩了。晚上，小宝贝躺在床上想：做错事要勇敢地说对不起。晚安，小宝贝，知错能改就是好孩子。', '成长启蒙', '📚', 3, 8, ['道歉', '知错', '成长']),
    _s('g003', '学会独立', '今天早上，小宝贝想要自己穿衣服。妈妈想要帮忙，可是小宝贝说：妈妈，我自己来。小宝贝认真地穿衣服。穿衣服的时候，小宝贝把扣子扣错了。妈妈笑着指出来。小宝贝重新扣好了扣子。穿完衣服，小宝贝又想要自己刷牙。妈妈给小宝贝准备好了牙刷和牙膏。小宝贝认真地刷着牙齿。刷完牙，小宝贝看着镜子里的自己，开心地笑了。晚上，小宝贝躺在床上想：我长大了，能自己做事情了。晚安，小宝贝，你正在一天天长大。', '成长启蒙', '📚', 2, 6, ['独立', '成长', '能力']),
    _s('g004', '学会感恩', '今天晚上，妈妈做了一桌子好菜。小宝贝吃得很开心。吃着吃着，小宝贝突然对妈妈说：妈妈，谢谢你每天给我做好吃的饭菜。妈妈愣了一下，然后开心地笑了。妈妈说：小宝贝真乖。爸爸也笑着说：小宝贝长大了。晚上，小宝贝躺在床上想：妈妈每天都很辛苦地照顾我。以后我要多帮帮妈妈。晚安，小宝贝，学会感恩，生活会更美好。', '成长启蒙', '📚', 3, 8, ['感恩', '妈妈', '爱']),
    _s('g005', '学会勇敢', '今天晚上，小宝贝想要自己一个人睡觉。可是，小宝贝有点怕黑。小宝贝对妈妈说：妈妈，我怕黑。妈妈给小宝贝留了一盏小夜灯。妈妈说：小宝贝别害怕，妈妈就在隔壁。小宝贝看着小夜灯，心里踏实了很多。小宝贝闭上眼睛，慢慢地睡着了。第二天早上，小宝贝对妈妈说：妈妈，昨天晚上我一个人睡觉了！妈妈笑着说：我的小宝贝真勇敢。晚安，小宝贝，勇敢一点，你会越来越棒。', '成长启蒙', '📚', 3, 8, ['勇敢', '独立', '成长']),
    _s('g006', '学会倾听', '今天，老师在课堂上讲了一个有趣的故事。小宝贝认真地听着。旁边的小朋友想要和小宝贝说话，小宝贝小声说：先别说话，听老师讲故事。老师讲完故事，问了小朋友们几个问题。小宝贝都答对了。老师表扬小宝贝说：小宝贝真聪明，听得很认真。晚上，小宝贝躺在床上，想着老师讲的故事。晚安，小宝贝，认真倾听，你会学到很多东西。', '成长启蒙', '📚', 3, 9, ['倾听', '学习', '认真']),
    _s('g007', '学会坚持', '今天，小宝贝在练习骑自行车。小宝贝练了很久都没有学会。小宝贝有点不开心。爸爸对小宝贝说：小宝贝，别放弃。坚持就是胜利。小宝贝听了爸爸的话，又继续练习。一次又一次，一次又一次。最后，小宝贝终于学会骑自行车了！小宝贝开心地大喊：我做到啦！晚上，小宝贝躺在床上想：原来坚持就会成功。晚安，小宝贝，遇到困难不要放弃，坚持一下就会成功。', '成长启蒙', '📚', 4, 10, ['坚持', '努力', '成功']),
    _s('g008', '学会节约', '今天，小宝贝在刷牙的时候，一直开着水龙头。妈妈走过来说：小宝贝，水是很珍贵的，我们要节约用水。小宝贝听了，赶紧把水龙头关上。妈妈给小宝贝讲了很多关于节约用水的道理。晚上，小宝贝在洗澡的时候，记得把水龙头关上了。妈妈笑着说：小宝贝真棒。晚安，小宝贝，学会节约，珍惜资源。', '成长启蒙', '📚', 3, 8, ['节约', '珍惜', '成长']),

    // ==== 恐龙世界 ====
    _s('d001', '可爱的小恐龙', '很久很久以前，在一个美丽的森林里住着一只小恐龙。小恐龙的名字叫圆圆。圆圆有一个圆圆的身体，还有一条长长的尾巴。圆圆每天都在森林里快乐地玩耍。有一天，圆圆在森林里遇到了一只大恐龙。大恐龙比圆圆大好多好多。可是大恐龙很温柔，一点也不可怕。大恐龙和圆圆一起玩耍，一起吃东西，一起看日落。他们成为了好朋友。晚安，小宝贝，恐龙世界也有温柔的好朋友。', '恐龙世界', '🦕', 3, 9, ['恐龙', '森林', '友谊']),
    _s('d002', '三角龙的角', '从前有一只小三角龙，它的名字叫尖尖。尖尖有三个漂亮的角。每天尖尖都会用自己的角帮爸爸妈妈做事情。有一天，妈妈说：尖尖，你帮妈妈把这块大石头搬开好不好？尖尖点点头。尖尖用自己的角用力地顶着大石头。一下，两下，三下。大石头终于被尖尖推开了！妈妈开心地说：尖尖，你真棒！晚安，小宝贝，有特长是一件很开心的事情。', '恐龙世界', '🦕', 3, 9, ['三角龙', '角', '帮忙']),
    _s('d003', '小恐龙学飞', '有一只小翼龙叫飞飞。飞飞想要学会飞。可是飞飞怎么也飞不起来。妈妈对飞飞说：孩子，别着急，慢慢来。妈妈带着飞飞，一步一步地练习。飞飞在山坡上跑啊跑啊，挥动着翅膀。一次又一次。最后，飞飞终于飞起来了！飞飞开心地在天空中飞来飞去。妈妈笑着说：飞飞，你真棒！晚安，小宝贝，慢慢来，你一定能学会新本领。', '恐龙世界', '🦕', 3, 10, ['翼龙', '飞翔', '学习']),
    _s('d004', '恐龙的午餐', '今天中午，小恐龙圆圆肚子饿了。圆圆想要找东西吃。圆圆走到了草地上。草地上长满了嫩嫩的草。圆圆开心地吃了起来。这时候，一只小恐龙走过来，说：圆圆，我能和你一起吃吗？圆圆说：当然可以。他们一起开心地吃着午餐。吃完午餐，他们一起躺在草地上晒太阳。阳光暖暖的，真舒服呀。晚安，小宝贝，和朋友一起吃饭最香了。', '恐龙世界', '🦕', 2, 7, ['恐龙', '午餐', '朋友']),

    // ==== 汽车乐园 ====
    _s('c001', '小红车的一天', '有一辆小红车叫红红。红红每天都在路上跑来跑去。今天早上，红红送小朋友去幼儿园。下午，红红送妈妈去超市。晚上，红红送爸爸去上班。忙碌了一天，红红有点累了。红红回到了车库。车库里很温暖。红红舒舒服服地休息。晚安，小宝贝，汽车也会累，也需要休息。', '汽车乐园', '🚗', 2, 6, ['汽车', '忙碌', '休息']),
    _s('c002', '小警车', '有一辆小警车叫嘟嘟。嘟嘟每天都在路上巡逻。有一天，嘟嘟看到一只小猫在马路中间。嘟嘟赶紧停下来。嘟嘟把小猫送到了安全的地方。小猫的主人看到了，开心地说：谢谢你！嘟嘟笑着说：不用谢，这是我应该做的。嘟嘟又继续巡逻去了。晚安，小宝贝，帮助别人是一件快乐的事情。', '汽车乐园', '🚗', 3, 8, ['警车', '帮助', '小猫']),
    _s('c003', '小救护车', '有一辆小救护车叫急急。急急每天都准备着帮助需要帮助的人。有一天，急急接到了一个电话：有人需要帮助。急急赶紧出发。路上的车辆都给急急让路。急急很快就到了目的地。急急把病人送到了医院。医生说：谢谢你，急急！你来得真及时。急急笑着说：这是我应该做的。晚安，小宝贝，关键时刻有人帮助真好。', '汽车乐园', '🚗', 3, 8, ['救护车', '帮助', '医院']),
    _s('c004', '消防车', '有一辆消防车叫水水。水水每天都在消防站里待命。有一天，水水接到了一个电话：有一个地方着火了。水水赶紧出发。水水鸣着警笛，很快就到了着火的地方。水水用它的大水管喷出了很多水。火很快就被扑灭了。人们都开心地说：谢谢你，水水！水水笑着说：不用谢，这是我应该做的。晚安，小宝贝，注意安全很重要。', '汽车乐园', '🚗', 3, 8, ['消防车', '火', '安全']),

    // ==== 魔法世界 ====
    _s('m001', '魔法小仙子', '从前有一个魔法小仙子叫星星。星星有一对漂亮的翅膀，还有一根魔法棒。星星每天都在花朵之间飞来飞去。有一天，星星遇到了一个迷路的小女孩。星星用魔法棒一指，就给小女孩指了回家的路。小女孩开心地回家了。星星笑着继续它的旅程。晚安，小宝贝，世界上有很多美好的事情。', '魔法世界', '✨', 3, 10, ['仙子', '魔法', '帮助']),
    _s('m002', '会说话的玩具', '今天晚上，小宝贝的玩具们开始说话了。小玩具车说：今天小宝贝带我去公园玩了，真开心！小娃娃说：小宝贝今天给我梳了漂亮的辫子，真好看！小熊说：小宝贝每天晚上都抱着我睡觉，真温暖！小宝贝躲在门口听着，开心地笑了。原来玩具们也有自己的想法呀。晚安，小宝贝，你的玩具们也很爱你。', '魔法世界', '✨', 3, 8, ['玩具', '说话', '魔法']),
    _s('m003', '魔法糖果', '有一天，小宝贝在公园里捡到了一颗漂亮的糖果。糖果是彩色的，闪闪发光。小宝贝把糖果放进了口袋里。晚上，小宝贝躺在床上，看着那颗糖果。突然，糖果说话了：小宝贝，你想吃我吗？小宝贝吓了一跳。糖果接着说：我是一颗魔法糖果。吃了我，你就会有一个甜甜的梦。小宝贝吃下了糖果。小宝贝做了一个甜甜的梦。晚安，小宝贝，祝你有个甜美的梦。', '魔法世界', '✨', 3, 9, ['糖果', '魔法', '梦']),

    // ==== 太空探索 ====
    _s('s001', '月亮上的旅行', '有一天，小宝贝乘坐着宇宙飞船去月亮上旅行。宇宙飞船飞得很快很快。穿过云层，穿过大气层，就到了月亮上。月亮上到处都是灰白色的岩石。小宝贝在月亮上跳了跳。因为月亮上没有重力，小宝贝跳得很高很高！小宝贝还看到了天上的地球。地球圆圆的，蓝蓝的，真美丽呀。玩了一会儿，小宝贝就坐宇宙飞船回家了。晚安，小宝贝，宇宙很大很大，等你来探索。', '太空探索', '🚀', 4, 10, ['月亮', '宇宙', '探索']),
    _s('s002', '小星星的故事', '天上有一颗小星星叫闪闪。闪闪每天晚上都要出来给小朋友们照亮。可是有一天，闪闪有点不舒服，不能出来了。天上其他的星星都来照顾闪闪。月亮妈妈也来照顾闪闪。过了几天，闪闪终于好了。闪闪又在天上一闪一闪地亮起来了。小朋友们看到闪闪又亮起来了，都开心地说：小星星又出来啦！晚安，小宝贝，朋友之间要互相照顾。', '太空探索', '🚀', 3, 9, ['星星', '月亮', '朋友']),
    _s('s003', '小小宇航员', '有一个小男孩叫明明。明明梦想成为一名宇航员。明明每天都在锻炼身体，学习科学知识。有一天，明明终于成为了一名宇航员。明明乘坐着宇宙飞船，飞到了太空中。明明在太空中看到了地球，看到了月亮，还看到了很多很多的星星。太空中的世界真美丽呀。明明开心得不得了。晚安，小宝贝，有梦想就去追吧，有一天你一定能实现。', '太空探索', '🚀', 4, 10, ['宇航员', '太空', '梦想']),

    // ==== 海洋奇缘 ====
    _s('o001', '小鲸鱼的歌', '在一个蓝色的大海里，住着一只小鲸鱼叫乐乐。乐乐最喜欢在大海里唱歌。乐乐的歌声很好听，大海里的其他鱼儿们都喜欢听乐乐唱歌。有一天，乐乐唱了一首歌，歌声传到了很远很远的地方。一只大海龟游过来说：乐乐，你的歌声真好听！乐乐笑着说：谢谢你！晚安，小宝贝，大海里也有美丽的音乐。', '海洋奇缘', '🌊', 3, 9, ['鲸鱼', '唱歌', '大海']),
    _s('o002', '海底的小城堡', '在大海的深处，有一座美丽的小城堡。小城堡是用珊瑚做的，五颜六色，真美丽呀。小城堡里住着许多小鱼。小鱼们每天都在小城堡里玩耍，吃饭，睡觉。有一天，一只小章鱼来到了小城堡。小章鱼想要在小城堡里住下来。小鱼们都欢迎小章鱼的到来。他们一起开心地生活在小城堡里。晚安，小宝贝，海底的世界也很美丽。', '海洋奇缘', '🌊', 3, 9, ['海底', '城堡', '小鱼']),
    _s('o003', '会发光的小鱼', '在大海的深处，住着一条会发光的小鱼叫亮亮。亮亮的身体会发出彩色的光。晚上的时候，亮亮就出来给其他的小鱼照亮回家的路。小鱼们都很感谢亮亮。有一天，亮亮生病了，不能发光了。其他的小鱼们都来看望亮亮。他们给亮亮带来了好吃的食物，还给亮亮讲了好听的故事。亮亮很快就好起来了。晚安，小宝贝，帮助别人，别人也会帮助你。', '海洋奇缘', '🌊', 3, 10, ['小鱼', '发光', '互助']),
  ];
}
